import HeroSection from "../components/common/HeroSection";
import SectionHeader from "../components/common/SectionHeader";
import LoadingSpinner from "../components/common/LoadingSpinner";
import EmptyState from "../components/common/EmptyState";
import ProductCard from "../components/products/ProductCard";
import useAsync from "../hooks/useAsync";
import { productService } from "../services/api";
import { industries, services } from "../utils/constants";

const HomePage = () => {
  const { data, loading } = useAsync(() => productService.getProducts());
  const featuredProducts = data?.data?.slice(0, 6) || [];

  return (
    <>
      <HeroSection
        eyebrow="Global Trade. Reliable Delivery."
        title="Import-export solutions built for long-term international partnerships."
        description="Asiduo Enterprises delivers premium export products, curated imports, and technical industrial sourcing with compliance-focused execution."
        primaryAction={{ label: "Explore Products", path: "/products" }}
        secondaryAction={{ label: "Request Quote", path: "/request-quote" }}
      />

      <section className="section">
        <div className="container">
          <SectionHeader
            title="Why Asiduo Enterprises"
            subtitle="We combine sourcing strength, documentation discipline, and responsive client support to move products across borders with confidence."
          />
          <div className="feature-grid">
            {[
              "Trusted supplier network across export and import categories",
              "Documentation and quality alignment for global trade",
              "Tailored packaging, MOQ planning, and logistics support",
              "Technical procurement support for hazardous-area equipment"
            ].map((item) => (
              <div className="info-card" key={item}>
                <p>{item}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="section section-muted">
        <div className="container">
          <SectionHeader
            title="Featured Products"
            subtitle="A focused range across consumer, agricultural, and industrial trade verticals."
          />
          {loading ? <LoadingSpinner message="Loading featured products..." /> : null}
          {!loading && featuredProducts.length === 0 ? (
            <EmptyState title="No products available" message="Seed the database or add products from the admin panel." />
          ) : null}
          <div className="product-grid">
            {featuredProducts.map((product) => (
              <ProductCard key={product._id} product={product} />
            ))}
          </div>
        </div>
      </section>

      <section className="section">
        <div className="container two-column">
          <div>
            <SectionHeader
              title="Services"
              subtitle="Commercial and operational support designed for smooth cross-border trade."
              align="left"
            />
            <div className="stack-list">
              {services.map((service) => (
                <div className="info-card" key={service}>
                  <p>{service}</p>
                </div>
              ))}
            </div>
          </div>
          <div>
            <SectionHeader
              title="Industries"
              subtitle="Serving a diverse portfolio of product-driven and compliance-led sectors."
              align="left"
            />
            <div className="stack-list">
              {industries.map((industry) => (
                <div className="info-card" key={industry}>
                  <p>{industry}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default HomePage;
